        }

        public override async Task Validation(LeaveType item, Result<LeaveType> executionResult)
        {
            if (await UOW.GetRepositoryAsync<LeaveType>().HasRecordsAsync(x => x.Code == item.Code && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(LeaveType.Code), "Code already exists"));
            }
        }
        public override async Task<LeaveType> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<LeaveType>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<LeaveType>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<LeaveType>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<LeaveType>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<LeaveType>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Code.Contains(search.Name)
                     || x.Name.Contains(search.Name)),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Code", ascending: !search.IsDescend);
        }
